" CDS view with OData annotation (S/4HANA)
@OData.publish: true
define view ZI_SalesOrder as select from vbak {
  key vbeln as SalesOrder,
      erdat as CreationDate,
      netwr as NetValue,
      waerk as Currency
}

@AbapCatalog.sqlViewName: 'ZV_SALESSUM'
@Analytics.dataCategory: #CUBE
define view ZC_SalesSummary
  as select from vbak
  association [0..*] to vbap as _Items
    on $projection.SalesOrder = _Items.vbeln
{
  key vbeln   as SalesOrder,
      erdat   as CreationDate,
      netwr   as NetValue,
      _Items
}
